  1	import React, { FC } from 'react';
  2	import { Controller, useFormContext } from 'react-hook-form';
  3	
  4	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
  5	import { ResourceIcon, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
  6	import {
  7	  Alert,
  8	  DropdownItem,
  9	  FormGroup,
 10	  FormHelperText,
 11	  HelperText,
 12	  HelperTextItem,
 13	} from '@patternfly/react-core';
 14	import Loading from '@utils/components/Loading/Loading';
 15	import Select from '@utils/components/Select/Select';
 16	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 17	import { getName } from '@utils/resources/shared';
 18	
 19	import AlternateService from './AlternateServicesSection';
 20	import { SERVICE_FIELD_ID, ServiceGroupVersionKind } from './constants';
 21	import TargetPort from './Targetport';
 22	
 23	type ServiceSelectorProps = {
 24	  namespace: string;
 25	};
 26	
 27	const ServiceSelector: FC<ServiceSelectorProps> = ({ namespace }) => {
 28	  const { control, setValue, watch } = useFormContext();
 29	
 30	  const selectedServiceName = watch('spec.to.name');
 31	
 32	  const { t } = useNetworkingTranslation();
 33	
 34	  const [services, loaded, error] = useK8sWatchResource<IoK8sApiCoreV1Service[]>({
 35	    groupVersionKind: ServiceGroupVersionKind,
 36	    isList: true,
 37	    namespace,
 38	  });
 39	
 40	  const selectedService = (services || []).find(
 41	    (service) => getName(service) === selectedServiceName,
 42	  );
 43	
 44	  if (error) return <Alert title={t('Error')}></Alert>;
 45	
 46	  return (
 47	    <>
 48	      <Controller
 49	        control={control}
 50	        name="spec.to.name"
 51	        render={({ field: { onChange, value } }) => (
 52	          <FormGroup fieldId={SERVICE_FIELD_ID} isRequired label={t('Service')}>
 53	            <Select
 54	              id={SERVICE_FIELD_ID}
 55	              selected={value}
 56	              toggleContent={
 57	                value ? (
 58	                  <>
 59	                    <ResourceIcon groupVersionKind={ServiceGroupVersionKind} /> {value}
 60	                  </>
 61	                ) : (
 62	                  t('Select a Service')
 63	                )
 64	              }
 65	            >
 66	              <>
 67	                {!loaded && <Loading />}
 68	                {loaded &&
 69	                  (services || []).map((service) => (
 70	                    <DropdownItem
 71	                      key={getName(service)}
 72	                      onClick={() => {
 73	                        onChange(getName(service));
 74	                        setValue('spec.port.targetPort', '');
 75	                      }}
 76	                      value={getName(service)}
 77	                    >
 78	                      <ResourceIcon groupVersionKind={ServiceGroupVersionKind} /> {getName(service)}
 79	                    </DropdownItem>
 80	                  ))}
 81	              </>
 82	            </Select>
 83	
 84	            <FormHelperText>
 85	              <HelperText>
 86	                <HelperTextItem>{t('Service to route to.')}</HelperTextItem>
 87	              </HelperText>
 88	            </FormHelperText>
 89	          </FormGroup>
 90	        )}
 91	        rules={{ required: true }}
 92	      />
 93	      {selectedService && (
 94	        <AlternateService
 95	          services={services?.filter((service) => getName(service) !== getName(selectedService))}
 96	        />
 97	      )}
 98	      <TargetPort service={selectedService} />
 99	    </>
100	  );
101	};
102	
103	export default ServiceSelector;

